import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getB2bProducts, getB2bProfile } from "../../features/b2b/b2bSlice";
import { getSocket } from "../../socket";
import B2bHeader from "./B2bHeader";
import {
  Search, Layers, AlertCircle, ArrowRight,
  ShieldAlert, Lock, SlidersHorizontal, X, Package,
} from "lucide-react";

/* ─────────────────────────────────────────────────────────────
   Design tokens — one place to change colours / radii
───────────────────────────────────────────────────────────── */
const badge = {
  IN_STOCK:     "bg-emerald-50 text-emerald-700 ring-1 ring-emerald-200",
  LOW_STOCK:    "bg-amber-50   text-amber-700   ring-1 ring-amber-200",
  OUT_OF_STOCK: "bg-red-50     text-red-600     ring-1 ring-red-200",
};

const categories = [
  { label: "All Items",               value: "" },
  { label: "Pharmaceuticals",         value: "PHARMACEUTICALS" },
  { label: "Surgical Instruments",    value: "SURGICAL_INSTRUMENTS" },
  { label: "Laboratory Reagents",     value: "LABORATORY_REAGENTS" },
  { label: "Diagnostic Equipment",    value: "DIAGNOSTIC_EQUIPMENT" },
  { label: "Medical Consumables",     value: "MEDICAL_CONSUMABLES" },
  { label: "PPE & Infection Control", value: "PPE_INFECTION_CONTROL" },
  { label: "Hospital Furniture",      value: "HOSPITAL_FURNITURE" },
  { label: "Pharmacy Supplies",       value: "PHARMACY_SUPPLIES" },
];

/* ─────────────────────────────────────────────────────────────
   Product Card
───────────────────────────────────────────────────────────── */
const ProductCard = ({ prod }) => {
  const imgSrc =
    prod.images?.[0]?.secure_url ||
    prod.images?.[0]?.url ||
    (typeof prod.images?.[0] === "string" ? prod.images[0] : null) ||
    prod.colors?.[0]?.images?.[0]?.secure_url ||
    prod.colors?.[0]?.images?.[0]?.url ||
    null;

  const status = prod.availabilityStatus || "OUT_OF_STOCK";
  const price  = parseFloat(prod.wholesalePrice || 0);
  const outOfStock = status === "OUT_OF_STOCK";

  return (
    <Link
      to={`/b2b/product/${prod.id}`}
      className="group flex flex-col h-full bg-white border border-slate-200/80 rounded-xl overflow-hidden shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-200 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-500/40"
    >
      {/* ── Image ── */}
      <div className="relative w-full aspect-[4/3] bg-slate-50 flex items-center justify-center overflow-hidden shrink-0">
        {imgSrc ? (
          <img
            src={imgSrc}
            alt={prod.title}
            className="w-full h-full object-cover group-hover:scale-[1.04] transition-transform duration-300"
          />
        ) : (
          <Package size={34} strokeWidth={1.25} className="text-slate-200" />
        )}
        <span className={`absolute top-2 left-2 inline-flex items-center text-[10px] font-semibold px-2 py-0.5 rounded-full whitespace-nowrap ${badge[status] || badge.OUT_OF_STOCK}`}>
          {status.replace(/_/g, " ")}
        </span>
      </div>

      {/* ── Body — flex-col so footer always sticks to bottom ── */}
      <div className="flex flex-col flex-1 p-3.5">

        {/* Top section — grows to fill space */}
        <div className="flex-1">
          {/* SKU */}
          <p className="text-[10px] font-medium text-slate-400 tracking-wider uppercase truncate mb-1">
            {prod.sku || "—"}
          </p>

          {/* Title — 2 lines max, consistent height */}
          <h3
            className={`text-[13px] font-semibold leading-[1.35] min-h-[2.7em] overflow-hidden transition-colors duration-150 ${
              outOfStock ? "text-slate-400" : "text-slate-900 group-hover:text-blue-600"
            }`}
            style={{
              display: "-webkit-box",
              WebkitLineClamp: 2,
              WebkitBoxOrient: "vertical",
              overflow: "hidden",
            }}
          >
            {prod.title}
          </h3>

          {/* Generic name — 1 line, reserved space */}
          <p className="text-[11px] text-slate-400 italic mt-0.5 h-[1.2em] truncate">
            {prod.genericName || ""}
          </p>

          {/* Specs */}
          <div className="mt-2 pt-2 border-t border-slate-100 grid grid-cols-2 gap-x-2 gap-y-0.5 text-[11px]">
            <span className="text-slate-400">MOQ</span>
            <span className="text-slate-700 font-medium text-right">{prod.minimumOrderQuantity || 1} units</span>
            <span className="text-slate-400">Unit</span>
            <span className="text-slate-700 font-medium text-right uppercase truncate">{prod.unitOfSale || "STD"}</span>
            {prod.caseQuantity > 1 && (
              <>
                <span className="text-slate-400">Case</span>
                <span className="text-slate-700 font-medium text-right">{prod.caseQuantity}/case</span>
              </>
            )}
          </div>
        </div>

        {/* ── Footer — always at bottom ── */}
        <div className="mt-3 pt-3 border-t border-slate-100 flex items-center gap-2">
          {/* Price — shrinks gracefully */}
          <div className="min-w-0 flex-1">
            <p className="text-[10px] text-slate-400 uppercase tracking-wider font-medium leading-none mb-0.5">Wholesale</p>
            <p className={`font-bold leading-none ${outOfStock ? "text-slate-300" : "text-slate-900"}`}>
              <span className="text-[15px]">{price.toLocaleString()}</span>
              <span className="text-[10px] font-normal text-slate-400 ml-1">ETB</span>
            </p>
          </div>

          {/* CTA — fixed size, never wraps */}
          <span className={`shrink-0 inline-flex items-center gap-1 text-[11px] font-semibold px-2.5 py-1.5 rounded-lg whitespace-nowrap transition-colors ${
            outOfStock
              ? "bg-slate-100 text-slate-400 cursor-not-allowed"
              : "bg-slate-900 text-white group-hover:bg-blue-600"
          }`}>
            View Details
            <ArrowRight size={12} className="group-hover:translate-x-0.5 transition-transform" />
          </span>
        </div>
      </div>
    </Link>
  );
};

/* ─────────────────────────────────────────────────────────────
   Skeleton card
───────────────────────────────────────────────────────────── */
const SkeletonCard = () => (
  <div className="flex flex-col bg-white border border-border rounded-xl overflow-hidden shadow-sm animate-pulse">
    <div className="w-full aspect-[4/3] bg-slate-100" />
    <div className="p-3.5 flex flex-col gap-2.5">
      <div className="h-2.5 w-1/4 bg-slate-100 rounded" />
      <div className="h-4 w-3/4 bg-slate-100 rounded" />
      <div className="h-3 w-1/2 bg-slate-100 rounded" />
      <hr className="border-slate-100" />
      <div className="h-3 w-full bg-slate-100 rounded" />
      <div className="h-8 w-full bg-slate-100 rounded-lg mt-1" />
    </div>
  </div>
);

/* ─────────────────────────────────────────────────────────────
   Main page
───────────────────────────────────────────────────────────── */
const B2bCatalog = () => {
  const dispatch = useDispatch();
  const [search,        setSearch       ] = useState("");
  const [b2bCategory,   setB2bCategory  ] = useState("");
  const [availability,  setAvailability ] = useState("");
  const [filtersOpen,   setFiltersOpen  ] = useState(false);
  const [profileLoaded, setProfileLoaded] = useState(false);

  const { products, profile, isLoading } = useSelector((s) => s.b2b);

  useEffect(() => {
    dispatch(getB2bProfile()).finally(() => setProfileLoaded(true));
  }, [dispatch]);

  useEffect(() => {
    const p = {};
    if (search)       p.search             = search;
    if (b2bCategory)  p.b2bCategory        = b2bCategory;
    if (availability) p.availabilityStatus = availability;
    dispatch(getB2bProducts(p));
  }, [dispatch, search, b2bCategory, availability]);

  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;
    const refresh = () => {
      const p = {};
      if (search)       p.search             = search;
      if (b2bCategory)  p.b2bCategory        = b2bCategory;
      if (availability) p.availabilityStatus = availability;
      dispatch(getB2bProducts(p));
    };
    socket.on("product:updated", refresh);
    return () => socket.off("product:updated", refresh);
  }, [dispatch, search, b2bCategory, availability]);

  const hasB2bAccess = profile?.customerType;
  const isVerified   = profile?.isVerified;
  const activeFilters = [b2bCategory, availability].filter(Boolean);

  return (
    <div className="min-h-screen bg-[#f9fafb]">
      <B2bHeader />

      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-10 py-7">

        {/* ── No access ── */}
        {profileLoaded && !hasB2bAccess && (
          <div className="mb-6 flex items-start gap-3 p-4 bg-red-50 border border-red-200 rounded-xl text-sm">
            <Lock size={18} className="text-red-500 shrink-0 mt-0.5" />
            <div>
              <p className="font-semibold text-red-800">B2B Access Not Enabled</p>
              <p className="text-red-600 text-xs mt-0.5">Contact your administrator to enable wholesale access for your account.</p>
            </div>
          </div>
        )}

        {/* ── Pending verification ── */}
        {profileLoaded && hasB2bAccess && !isVerified && (
          <div className="mb-6 flex items-start gap-3 p-4 bg-amber-50 border border-amber-200 rounded-xl text-sm">
            <ShieldAlert size={18} className="text-amber-500 shrink-0 mt-0.5" />
            <div>
              <p className="font-semibold text-amber-900">Account Pending Verification</p>
              <p className="text-amber-700 text-xs mt-0.5">You can browse and order via Chapa payment. Credit terms become available after verification.</p>
            </div>
          </div>
        )}

        {/* ── Toolbar ── */}
        <div className="bg-white border border-border rounded-xl shadow-sm mb-6 overflow-hidden">

          {/* Main row */}
          <div className="flex items-center gap-2.5 px-3 py-3">
            {/* Search */}
            <div className="relative flex-1 min-w-0">
              <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
              <input
                type="text"
                placeholder="Search by title, SKU, or generic name…"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-9 pr-8 h-9 bg-slate-50 border border-slate-200 rounded-lg text-[13px] placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition-all"
              />
              {search && (
                <button onClick={() => setSearch("")} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 p-0.5">
                  <X size={13} />
                </button>
              )}
            </div>

            {/* Desktop filters */}
            <div className="hidden sm:flex items-center gap-2 shrink-0">
              <select
                value={b2bCategory}
                onChange={(e) => setB2bCategory(e.target.value)}
                className="h-9 px-3 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/20 cursor-pointer hover:bg-slate-100 transition-colors"
              >
                {categories.map((c) => (
                  <option key={c.value} value={c.value}>{c.label}</option>
                ))}
              </select>

              <select
                value={availability}
                onChange={(e) => setAvailability(e.target.value)}
                className="h-9 px-3 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/20 cursor-pointer hover:bg-slate-100 transition-colors"
              >
                <option value="">All Stock Statuses</option>
                <option value="IN_STOCK">In Stock</option>
                <option value="LOW_STOCK">Low Stock</option>
                <option value="OUT_OF_STOCK">Out of Stock</option>
              </select>
            </div>

            {/* Mobile filter button */}
            <button
              onClick={() => setFiltersOpen(!filtersOpen)}
              className={`sm:hidden h-9 px-3 rounded-lg border text-[13px] font-medium flex items-center gap-1.5 transition-colors shrink-0 ${
                filtersOpen || activeFilters.length
                  ? "bg-blue-600 text-white border-blue-600"
                  : "bg-slate-50 border-slate-200 text-slate-600"
              }`}
            >
              <SlidersHorizontal size={14} />
              {activeFilters.length > 0 && (
                <span className="w-4 h-4 rounded-full bg-white text-blue-600 text-[9px] font-bold flex items-center justify-center">
                  {activeFilters.length}
                </span>
              )}
            </button>
          </div>

          {/* Mobile filter panel */}
          {filtersOpen && (
            <div className="sm:hidden px-3 pb-3 flex flex-col gap-2 border-t border-slate-100 pt-2.5">
              <select value={b2bCategory} onChange={(e) => setB2bCategory(e.target.value)}
                className="h-9 px-3 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-700 focus:outline-none">
                {categories.map((c) => <option key={c.value} value={c.value}>{c.label}</option>)}
              </select>
              <select value={availability} onChange={(e) => setAvailability(e.target.value)}
                className="h-9 px-3 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-700 focus:outline-none">
                <option value="">All Stock Statuses</option>
                <option value="IN_STOCK">In Stock</option>
                <option value="LOW_STOCK">Low Stock</option>
                <option value="OUT_OF_STOCK">Out of Stock</option>
              </select>
            </div>
          )}

          {/* Active filter chips */}
          {activeFilters.length > 0 && (
            <div className="px-3 pb-2.5 flex items-center gap-1.5 flex-wrap border-t border-slate-100 pt-2">
              <span className="text-[11px] text-slate-400 font-medium mr-1">Active:</span>
              {b2bCategory && (
                <button onClick={() => setB2bCategory("")}
                  className="inline-flex items-center gap-1 text-[11px] font-medium px-2 py-0.5 bg-blue-50 text-blue-700 rounded-full ring-1 ring-blue-200 hover:bg-blue-100 transition-colors">
                  {categories.find(c => c.value === b2bCategory)?.label}
                  <X size={10} />
                </button>
              )}
              {availability && (
                <button onClick={() => setAvailability("")}
                  className="inline-flex items-center gap-1 text-[11px] font-medium px-2 py-0.5 bg-blue-50 text-blue-700 rounded-full ring-1 ring-blue-200 hover:bg-blue-100 transition-colors">
                  {availability.replace(/_/g, " ")}
                  <X size={10} />
                </button>
              )}
              <button onClick={() => { setB2bCategory(""); setAvailability(""); setSearch(""); }}
                className="text-[11px] font-medium text-slate-400 hover:text-slate-700 ml-1 underline underline-offset-2">
                Clear all
              </button>
            </div>
          )}
        </div>

        {/* ── Count ── */}
        {!isLoading && products?.length > 0 && (
          <p className="text-[12px] text-slate-400 font-medium mb-4">
            Showing <span className="font-semibold text-slate-600">{products.length}</span> product{products.length !== 1 ? "s" : ""}
          </p>
        )}

        {/* ── Grid ── */}
        {isLoading ? (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
            {Array.from({ length: 10 }).map((_, i) => <SkeletonCard key={i} />)}
          </div>
        ) : products?.length > 0 ? (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 items-stretch">
            {products.map((prod) => <ProductCard key={prod.id} prod={prod} />)}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-24 bg-white border border-border rounded-xl shadow-sm text-center px-6">
            <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center mb-4">
              <AlertCircle size={28} className="text-slate-300" />
            </div>
            <p className="text-[14px] font-semibold text-slate-700">No products found</p>
            <p className="text-[12px] text-slate-400 mt-1 max-w-xs">Try adjusting your search or filters.</p>
            {activeFilters.length > 0 && (
              <button onClick={() => { setB2bCategory(""); setAvailability(""); setSearch(""); }}
                className="mt-4 h-9 px-4 bg-slate-900 text-white text-[12px] font-medium rounded-lg hover:bg-blue-600 transition-colors">
                Clear Filters
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default B2bCatalog;
